{"query":"
query countries($locale: SupportedLocale!) {
  countries(locale: $locale) {
    name
    code
    continent
    phoneNumberPrefix
    autocompletionField
    provinceKey
    labels {
      address1
      address2
      city
      company
      country
      firstName
      lastName
      phone
      postalCode
      zone
    }
    optionalLabels {
      address2
    }
    formatting {
      edit
      show
    }
    zones {
      name
      code
    }
  }
}

query country($countryCode: SupportedCountry!, $locale: SupportedLocale!) {
  country(countryCode: $countryCode, locale: $locale) {
    name
    code
    continent
    phoneNumberPrefix
    autocompletionField
    provinceKey
    labels {
      address1
      address2
      city
      company
      country
      firstName
      lastName
      phone
      postalCode
      zone
    }
    optionalLabels {
      address2
    }
    formatting {
      edit
      show
    }
    zones {
      name
      code
    }
  }
}
","operationName":"countries","variables":{"locale":"EN_DE","includeHiddenZones":false}}

{"query":"
query validation($address: AddressInput!, $locale: String!, $matchingStrategy: MatchingStrategy) {
  validation(address: $address, locale: $locale, matchingStrategy: $matchingStrategy) {
    validationScope
    locale
    fields {
      name
      value
    }
    concerns {
      fieldNames
      code
      type
      typeLevel
      suggestionIds
      message
    }
    id
    suggestions {
      id
      address1
      streetName
      streetNumber
      address2
      line2
      neighborhood
      city
      zip
      provinceCode
      province
      countryCode
    }
  }
}
","operationName":"validation","variables":{"address":{"address1":"wedasfa","countryCode":"DE","zip":"2342435","city":"Tel Aviv"},"locale":"en-DE"}}

